HEAD.script:

		function PageOnLoad() {
		parent.PageShowWait(false);
	}

	function openAviso(pOIAviso) {
		parent.ShowDetail(pOIAviso);
}

function showPostulado(pOIAviso) {
	var objImg = document.getElementById("img_" + pOIAviso);
	if (objImg.style.display == 'none')
		objImg.style.display = "";
	else
		objImg.style.display = "none";
}
